function numDecodings(s: string): number {
  if (!s || s[0] === "0") return 0;
  let p2 = 1, p1 = 1;
  for (let i = 1; i < s.length; i++) {
    let cur = 0;
    if (s[i] !== "0") cur += p1;
    const two = parseInt(s.slice(i - 1, i + 1), 10);
    if (two >= 10 && two <= 26) cur += p2;
    p2 = p1; p1 = cur;
  }
  return p1;
}
